/**
 * Query-level tests for the type-matrix specializations: class predicate usage (GROUP BY type, predicate) and class
 * linkage (GROUP BY source type, target type) collapse into one subject-ordered co-scan instead of a join.
 */
public class LmdbTypeMatrixTest {

	private static final String EX = "http://example.com/";

	private static final String USAGE_MATRIX = "PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>\n"
			+ "SELECT ?type ?p (COUNT(*) AS ?statements) WHERE {\n"
			+ "  ?instance a ?type .\n"
			+ "  ?instance ?p ?o .\n"
			+ "  FILTER(?p != rdf:type)\n"
			+ "}\n"
			+ "GROUP BY ?type ?p\n"
			+ "ORDER BY DESC(?statements) ?type ?p";

	private static final String LINKAGE_MATRIX = "PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>\n"
			+ "SELECT ?sourceType ?targetType (COUNT(*) AS ?links) WHERE {\n"
			+ "  ?source ?p ?target .\n"
			+ "  ?source a ?sourceType .\n"
			+ "  ?target a ?targetType .\n"
			+ "  FILTER(?p != rdf:type)\n"
			+ "}\n"
			+ "GROUP BY ?sourceType ?targetType\n"
			+ "ORDER BY DESC(?links) ?sourceType ?targetType";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@AfterEach
	public void tearDown() {
		System.clearProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY);
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	public void usageMatrixCollapsesIntoCoScan() {
		Map<String, Long> expected = openRepository(0).usage;

		long before = LmdbNativeTypeMatrix.RUNS.get();
		assertThat(matrix(USAGE_MATRIX, "type", "p", "statements")).isEqualTo(expected);
		assertThat(LmdbNativeTypeMatrix.RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void linkageMatrixCollapsesIntoCoScan() {
		Map<String, Long> expected = openRepository(0).linkage;

		long before = LmdbNativeTypeMatrix.RUNS.get();
		assertThat(matrix(LINKAGE_MATRIX, "sourceType", "targetType", "links")).isEqualTo(expected);
		assertThat(LmdbNativeTypeMatrix.RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void matricesMatchOnLargerRandomDatasetInParallel() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		Expected expected = openRepository(4000);

		long before = LmdbNativeTypeMatrix.RUNS.get();
		assertThat(matrix(USAGE_MATRIX, "type", "p", "statements")).isEqualTo(expected.usage);
		assertThat(matrix(LINKAGE_MATRIX, "sourceType", "targetType", "links")).isEqualTo(expected.linkage);
		assertThat(LmdbNativeTypeMatrix.RUNS.get()).isGreaterThan(before + 1);
	}

	@Test
	public void unrelatedFilterFallsBackAndStaysCorrect() {
		openRepository(0);

		long before = LmdbNativeTypeMatrix.RUNS.get();
		// a filter reading the object variable is outside the co-scan's claim
		List<BindingSet> rows;
		try (SailRepositoryConnection conn = repository.getConnection()) {
			rows = QueryResults.asList(conn.prepareTupleQuery(
					"PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>\n"
							+ "SELECT ?type ?p (COUNT(*) AS ?statements) WHERE {\n"
							+ "  ?instance a ?type .\n"
							+ "  ?instance ?p ?o .\n"
							+ "  FILTER(isIRI(?o))\n"
							+ "}\n"
							+ "GROUP BY ?type ?p")
					.evaluate());
		}
		assertThat(rows).isNotEmpty();
		assertThat(LmdbNativeTypeMatrix.RUNS.get()).isEqualTo(before);
	}

	private static final class Expected {
		final Map<String, Long> usage = new HashMap<>();
		final Map<String, Long> linkage = new HashMap<>();
	}

	/**
	 * Loads a graph with typed and untyped nodes (some multi-typed), literal objects, and rdf:type edges, and computes
	 * both expected matrices in plain Java.
	 */
	private Expected openRepository(int extraRandomEdges) {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc,psoc")));
		Expected expected = new Expected();
		Map<String, List<String>> typesOf = new HashMap<>();
		List<String[]> edges = new java.util.ArrayList<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			java.util.function.BiConsumer<String, String> addType = (node, type) -> {
				conn.add(vf.createIRI(EX, node), RDF.TYPE, vf.createIRI(EX, type));
				typesOf.computeIfAbsent(node, k -> new java.util.ArrayList<>()).add(type);
			};
			addType.accept("a", "Person");
			addType.accept("b", "Person");
			addType.accept("b", "Employee"); // multi-typed
			addType.accept("c", "Place");
			addType.accept("d", "Place");
			// "u" stays untyped
			java.util.function.BiConsumer<String[], Void> addEdge = (edge, ignored) -> {
				conn.add(vf.createIRI(EX, edge[0]), vf.createIRI(EX, edge[1]), vf.createIRI(EX, edge[2]));
				edges.add(edge);
			};
			addEdge.accept(new String[] { "a", "knows", "b" }, null);
			addEdge.accept(new String[] { "a", "knows", "c" }, null);
			addEdge.accept(new String[] { "b", "visits", "c" }, null);
			addEdge.accept(new String[] { "b", "visits", "d" }, null);
			addEdge.accept(new String[] { "c", "near", "d" }, null);
			addEdge.accept(new String[] { "u", "knows", "a" }, null);
			addEdge.accept(new String[] { "a", "knows", "u" }, null);
			// a literal-valued statement: counts for usage, contributes nothing to linkage
			conn.add(vf.createIRI(EX, "a"), vf.createIRI(EX, "name"), vf.createLiteral("Alice"));
			edges.add(new String[] { "a", "name", null });
			Random random = new Random(19);
			java.util.Set<String> seenEdges = new java.util.HashSet<>();
			for (int i = 0; i < extraRandomEdges; i++) {
				String source = "n" + random.nextInt(300);
				String target = "n" + random.nextInt(300);
				String p = "p" + random.nextInt(5);
				if (typesOf.get(source) == null && random.nextInt(4) != 0) {
					addType.accept(source, "T" + random.nextInt(7));
				}
				if (typesOf.get(target) == null && random.nextInt(4) != 0) {
					addType.accept(target, "T" + random.nextInt(7));
				}
				if (seenEdges.add(source + "|" + p + "|" + target)) {
					addEdge.accept(new String[] { source, p, target }, null);
				}
			}
		}
		for (String[] edge : edges) {
			for (String sourceType : typesOf.getOrDefault(edge[0], List.of())) {
				expected.usage.merge(EX + sourceType + "|" + EX + edge[1], 1L, Long::sum);
				if (edge[2] != null) {
					for (String targetType : typesOf.getOrDefault(edge[2], List.of())) {
						expected.linkage.merge(EX + sourceType + "|" + EX + targetType, 1L, Long::sum);
					}
				}
			}
		}
		return expected;
	}

	private Map<String, Long> matrix(String query, String key1, String key2, String countBinding) {
		Map<String, Long> counts = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			for (BindingSet bs : QueryResults.asList(conn.prepareTupleQuery(query).evaluate())) {
				counts.put(bs.getValue(key1).stringValue() + "|" + bs.getValue(key2).stringValue(),
						((Literal) bs.getValue(countBinding)).longValue());
			}
		}
		return counts;
	}
}
